{"content":"from __future__ import annotations

from typing import Dict, List, Optional, Tuple

from app.models.object import CalculateRequest, TeacherObject, TeacherStatus, CourseType
from app.models.record import (
    AuditRecord,
    CalculateResult,
    RecordStore,
    RuleHitDetail,
)
from app.models.rule import (
    RuleAction,
    RuleDefinition,
    RiskLevel,
    calculate_allowance,
    get_rules,
)
from app.models.state import (
    InvalidTransitionError,
    TaskState,
    TaskStatus,
)


class AllowanceEngine:
    def __init__(self, store: Optional[RecordStore] = None) -> None:
        self.store = store or RecordStore()
        self._states: Dict[str, TaskState] = {}

    def _get_state(self, business_id: str) -> TaskState:
        if business_id not in self._states:
            self._states[business_id] = TaskState(business_id=business_id)
        return self._states[business_id]

    def _evaluate_condition(self, teacher: TeacherObject, condition) -> bool:
        field = condition.field
        op = condition.operator
        val = condition.value

        actual = getattr(teacher, field, None)
        if actual is None:
            return False

        actual_str = str(actual.value) if hasattr(actual, "value") else str(actual)

        if op == "eq":
            return actual_str == val
        elif op == "neq":
            return actual_str != val
        elif op == "gt":
            try:
                return float(actual_str) > float(val)
            except (ValueError, TypeError):
                return False
        elif op == "lt":
            try:
                return float(actual_str) < float(val)
            except (ValueError, TypeError):
                return False
        elif op == "in":
            return actual_str in val.split(",")
        elif op == "not_in":
            return actual_str not in val.split(",")
        return False

    def _evaluate_rules(
        self, teacher: TeacherObject, rules: List[RuleDefinition]
    ) -> Tuple[RuleAction, List[RuleHitDetail], List[str]]:
        hits: List[RuleHitDetail] = []
        risk_flags: List[str] = []

        sorted_rules = sorted(
            [r for r in rules if r.enabled], key=lambda r: -r.priority
        )

        for rule in sorted_rules:
            all_match = all(
                self._evaluate_condition(teacher, c) for c in rule.conditions
            )
            if all_match and rule.conditions:
                hits.append(
                    RuleHitDetail(
                        rule_id=rule.rule_id,
                        rule_name=rule.name,
                        risk_level=rule.risk_level,
                        action=rule.action,
                        reason=rule.description,
                    )
                )
                risk_flags.append(f"{rule.rule_id}:{rule.risk_level.value}")

        if not hits:
            return RuleAction.PASS, hits, risk_flags

        has_block = any(h.action == RuleAction.BLOCK for h in hits)
        has_pending = any(h.action == RuleAction.PENDING_REVIEW for h in hits)

        if has_block:
            return RuleAction.BLOCK, hits, risk_flags
        if has_pending:
            return RuleAction.PENDING_REVIEW, hits, risk_flags

        return RuleAction.PASS, hits, risk_flags

    def _build_reason(
        self,
        action: RuleAction,
        hits: List[RuleHitDetail],
        teacher: TeacherObject,
        amount: float,
    ) -> str:
        if action == RuleAction.PASS and not hits:
            return (
                f"教师{teacher.name}({teacher.teacher_id})核算通过，"
                f"课时{teacher.course_hours}，津贴{amount}元"
            )
        if action == RuleAction.BLOCK:
            reasons = "；".join(h.reason for h in hits if h.action == RuleAction.BLOCK)
            return f"核算拦截：{reasons}"
        if action == RuleAction.PENDING_REVIEW:
            reasons = "；".join(
                h.reason for h in hits if h.action == RuleAction.PENDING_REVIEW
            )
            return f"待人工复核：{reasons}"
        return "核算通过"

    def calculate(self, request: CalculateRequest) -> CalculateResult:
        state = self._get_state(request.business_id)

        if state.current_status not in (
            TaskStatus.SUBMITTED,
            TaskStatus.BLOCKED,
            TaskStatus.REVIEW_REJECTED,
        ):
            existing = self.store.get_result(request.business_id)
            if existing:
                return existing
            return CalculateResult(
                business_id=request.business_id,
                teacher_id=request.teacher.teacher_id,
                final_action=RuleAction.BLOCK,
                task_status=state.current_status,
                readable_reason=f"任务状态为{state.current_status.value}，不允许重复核算",
            )

        state.transition(TaskStatus.PROCESSING, operator=request.operator)

        rules = get_rules(request.rule_version)
        action, hits, risk_flags = self._evaluate_rules(request.teacher, rules)

        amount = calculate_allowance(
            course_hours=request.teacher.course_hours,
            course_type=request.teacher.course_type,
            teacher_status=request.teacher.status,
            base_rate=request.teacher.base_rate,
        )

        course_type_name = request.teacher.course_type.value
        status_name = request.teacher.status.value
        multiplier = {
            CourseType.LECTURE: 1.0,
            CourseType.LAB: 1.2,
            CourseType.SEMINAR: 1.1,
            CourseType.PRACTICE: 1.3,
        }.get(request.teacher.course_type, 1.0)
        status_factor = {
            TeacherStatus.ACTIVE: 1.0,
            TeacherStatus.SUSPENDED: 0.0,
            TeacherStatus.RETIRED: 0.5,
            TeacherStatus.ON_LEAVE: 0.3,
        }.get(request.teacher.status, 0.0)

        calc_detail = (
            f"课时{request.teacher.course_hours} × 基础费率{request.teacher.base_rate}元"
            f" × 课程类型系数{multiplier}({course_type_name})"
            f" × 状态系数{status_factor}({status_name})"
            f" = {amount}元"
        )

        readable_reason = self._build_reason(action, hits, request.teacher, amount)

        if action == RuleAction.PASS and not hits:
            state.transition(TaskStatus.PASSED, operator=request.operator)
            task_status = TaskStatus.PASSED
        elif action == RuleAction.BLOCK:
            state.transition(
                TaskStatus.BLOCKED, operator=request.operator, reason=readable_reason
            )
            task_status = TaskStatus.BLOCKED
        elif action == RuleAction.PENDING_REVIEW:
            state.transition(
                TaskStatus.PENDING_REVIEW,
                operator=request.operator,
                reason=readable_reason,
            )
            task_status = TaskStatus.PENDING_REVIEW
        else:
            state.transition(TaskStatus.PASSED, operator=request.operator)
            task_status = TaskStatus.PASSED

        result = CalculateResult(
            business_id=request.business_id,
            teacher_id=request.teacher.teacher_id,
            allowance_amount=amount,
            calculation_detail=calc_detail,
            final_action=action,
            task_status=task_status,
            readable_reason=readable_reason,
            rule_hits=hits,
            risk_flags=risk_flags,
        )

        self.store.save_result(request.business_id, result)

        self.store.append_record(
            AuditRecord(
                record_id=f"{request.business_id}-calc",
                business_id=request.business_id,
                teacher_id=request.teacher.teacher_id,
                operator=request.operator,
                action=f"calculate:{action.value}",
                detail=readable_reason,
                metadata=result.model_dump(),
            )
        )

        return result

    def review(
        self,
        business_id: str,
        approved: bool,
        operator: str,
        reason: str = "",
    ) -> CalculateResult:
        state = self._get_state(business_id)

        if state.current_status != TaskStatus.PENDING_REVIEW:
            return CalculateResult(
                business_id=business_id,
                teacher_id="",
                final_action=RuleAction.BLOCK,
                task_status=state.current_status,
                readable_reason=f"当前状态{state.current_status.value}不可复核，仅待复核状态允许复核",
            )

        if approved:
            state.transition(
                TaskStatus.REVIEW_APPROVED, operator=operator, reason=reason
            )
            existing = self.store.get_result(business_id)
            task_status = TaskStatus.REVIEW_APPROVED
            if existing:
                existing.task_status = task_status
                existing.final_action = RuleAction.PASS
                existing.readable_reason = f"复核通过：{reason}" if reason else "复核通过"
                self.store.save_result(business_id, existing)
        else:
            state.transition(
                TaskStatus.REVIEW_REJECTED, operator=operator, reason=reason
            )
            existing = self.store.get_result(business_id)
            task_status = TaskStatus.REVIEW_REJECTED
            if existing:
                existing.task_status = task_status
                existing.final_action = RuleAction.BLOCK
                existing.readable_reason = f"复核驳回：{reason}" if reason else "复核驳回"
                self.store.save_result(business_id, existing)

        self.store.append_record(
            AuditRecord(
                record_id=f"{business_id}-review",
                business_id=business_id,
                teacher_id=existing.teacher_id if existing else "",
                operator=operator,
                action=f"review:{'approved' if approved else 'rejected'}",
                detail=reason,
            )
        )

        return self.store.get_result(business_id) or CalculateResult(
            business_id=business_id,
            teacher_id="",
            final_action=RuleAction.BLOCK,
            task_status=task_status,
            readable_reason="复核完成",
        )

    def batch_calculate(
        self, requests: List[CalculateRequest]
    ) -> List[CalculateResult]:
        return [self.calculate(req) for req in requests]

    def get_state(self, business_id: str) -> Optional[TaskState]:
        return self._states.get(business_id)

    def replay(self, business_id: str) -> List[Dict]:
        records = self.store.replay_by_business_id(business_id)
        state = self._states.get(business_id)
        result = {
            "audit_records": [r.model_dump() for r in records],
            "state_transitions": state.replay() if state else [],
        }
        return [result]
