{"content":"from __future__ import annotations

from typing import Dict, List, Optional

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel, Field

from app.engine.calculator import AllowanceEngine
from app.models.object import CalculateRequest, TeacherObject, TimeWindow
from app.models.record import CalculateResult
from app.models.rule import RuleAction
from app.models.state import TaskStatus

router = APIRouter(prefix="/api/v1/allowance", tags=["课时津贴核算"])

engine = AllowanceEngine()


class ReviewRequest(BaseModel):
    business_id: str = Field(..., description="业务编号")
    approved: bool = Field(..., description="是否通过复核")
    operator: str = Field(..., description="复核操作人")
    reason: str = Field(default="", description="复核原因说明")


class BatchCalculateRequest(BaseModel):
    requests: List[CalculateRequest] = Field(..., description="批量核算请求列表")


class ReplayResponse(BaseModel):
    business_id: str
    audit_records: List[Dict] = Field(default_factory=list)
    state_transitions: List[Dict] = Field(default_factory=list)


@router.post("/calculate", response_model=CalculateResult)
def calculate_allowance(request: CalculateRequest):
    result = engine.calculate(request)
    return result


@router.post("/batch-calculate", response_model=List[CalculateResult])
def batch_calculate(request: BatchCalculateRequest):
    results = engine.batch_calculate(request.requests)
    return results


@router.post("/review", response_model=CalculateResult)
def review_task(request: ReviewRequest):
    result = engine.review(
        business_id=request.business_id,
        approved=request.approved,
        operator=request.operator,
        reason=request.reason,
    )
    return result


@router.get("/replay/{business_id}", response_model=List[Dict])
def replay_business(business_id: str):
    data = engine.replay(business_id)
    if not data:
        raise HTTPException(status_code=404, detail=f"未找到业务编号 {business_id} 的记录")
    return data


@router.get("/status/{business_id}")
def get_task_status(business_id: str):
    state = engine.get_state(business_id)
    if not state:
        raise HTTPException(status_code=404, detail=f"未找到业务编号 {business_id} 的状态")
    result = engine.store.get_result(business_id)
    return {
        "business_id": business_id,
        "current_status": state.current_status.value,
        "is_terminal": state.is_terminal(),
        "transitions": state.replay(),
        "result": result.model_dump() if result else None,
    }
